CREATE PROC [dbo].[CREATE_ATADJ] @FromDate datetime, @ToDate datetime AS IF OBJECT_ID('ATADJ','U') IS NOT NULL DROP TABLE ATADJ IF OBJECT_ID('ATADJ_Info','U') IS NOT NULL DROP TABLE ATADJ_Info CREATE TABLE ATADJ ([Place Of Supply] varchar(32) ,[Rate] decimal ,[Gross Advance Adjusted] decimal ,[CESS Amount] decimal ) CREATE TABLE ATADJ_Info ( [Total Advance Adjusted] decimal, [Total Cess] decimal ) INSERT INTO ATADJ_Info VALUES(0,0) IF OBJECT_ID('ATADJ_Header','U') IS NULL CREATE TABLE ATADJ_Header ( [Summary For Advance Adjusted (11B) ] Char(1)) INSERT INTO InfoTable Values('ATADJ',2,'<<Default>>','ATADJ',8) 